import { useState, useCallback } from "react";
import { useNavigate } from "react-router-dom";
import styles from "./Leadership.module.css";
import Popup from './components/Popup';
import './components/Popup.css';
import GridItem from './components/GridItem';

import leadership_lines from '../images/leadership_lines.svg';
import keyclub from '../images/keyclub.png';
import mathletes from '../images/mathletes.png';
import turtlehacks from '../images/turtlehacks.png';
import lhss from '../images/lhss.png';

const Leadership = () => {
  const navigate = useNavigate();

  const onHomeTextClick = useCallback(() => {
    navigate("/");
  }, [navigate]);

  const onProjectsTextClick = useCallback(() => {
    navigate("/projects");
  }, [navigate]);

  const onLeadershipTextClick = useCallback(() => {
    navigate("/leadership");
  }, [navigate]);

  const onTurtleHacksImageClick = useCallback(() => {
    window.open("https://www.turtlehacks.com/");
  }, []);

  const [popupKeyClub, openKeyClub] = useState(false);
  const [popupMathletes, openMathletes] = useState(false);
  const [popupStudentLeadership, openStudentLeadership] = useState(false);
  const [popupTurtleHacks, openTurtleHacks] = useState(false);
  const [popupAKCSE, openAKCSE] = useState(false);
  const [popupBodyInDepth, openBodyInDepth] = useState(false);
  const [popupStudySpace, openStudySpace] = useState(false);

  return (
    <div className={styles.leadership}>
      <div className={styles.header}>
        <div className={styles.headerBackground} />
        <div className={styles.home} onClick={onHomeTextClick}>
          Home
        </div>
        <div className={styles.projects} onClick={onProjectsTextClick}>
          Projects
          </div>
        <div className={styles.leadership1} onClick={onLeadershipTextClick}>
          Leadership
        </div>

      <div className={styles.text}>
        <b className={styles.heading1}>Leadership</b>
        <br/>
        <b className={styles.heading2}>Experiences</b>

        <div className = {styles.gridContainer} style = {{boxShadow: "10px 10px grey"}}>
          <GridItem children="LHSS Key Club: President" trigger={popupKeyClub} setTrigger={openKeyClub}></GridItem>          
          <GridItem children="LHSS Mathletes: Executive" trigger={popupMathletes} setTrigger={openMathletes}></GridItem>
          <GridItem children="Student Leadership" trigger={popupStudentLeadership} setTrigger={openStudentLeadership}></GridItem>
          <GridItem children="TurtleHacks: Logistics Executive" trigger={popupTurtleHacks} setTrigger={openTurtleHacks}></GridItem>
          <GridItem children="AKCSE: Marketing Specialist" trigger={popupAKCSE} setTrigger={openAKCSE}></GridItem>          
          <GridItem children="BodyInDepth" trigger={popupBodyInDepth} setTrigger={openBodyInDepth}></GridItem>
          <GridItem children="StudySpace" trigger={popupStudySpace} setTrigger={openStudySpace}></GridItem>
        </div>

        <Popup trigger={popupKeyClub} setTrigger={openKeyClub}><h3>Key Club</h3></Popup>
        <Popup trigger={popupMathletes} setTrigger={openMathletes}><h3>Mathletes</h3></Popup>
        <Popup trigger={popupStudentLeadership} setTrigger={openStudentLeadership}><h3>Student Leadership</h3></Popup>
        <Popup trigger={popupTurtleHacks} setTrigger={openTurtleHacks}><h3>TurtleHacks</h3></Popup>
        <Popup trigger={popupAKCSE} setTrigger={openAKCSE}><h3>AKCSE: Marketing Specialist</h3></Popup>
        <Popup trigger={popupBodyInDepth} setTrigger={openBodyInDepth}><h3>BodyInDepth</h3></Popup>
        <Popup trigger={popupStudySpace} setTrigger={openStudySpace}><h3>StudySpace</h3></Popup>
      </div>
      </div>
    </div>
  );
};

export default Leadership;
